def _mud_connect(client, host, port, name, password):
    result = client.connect(host=host, port=port, name=name, password=password)
    if result.get("ok"):
        return result["data"]
    return f"error: {result.get('error', 'unknown error')}"


def _mud_disconnect(client):
    result = client.disconnect()
    if result.get("ok"):
        return result["data"]
    return f"error: {result.get('error', 'unknown error')}"


def _mud_status(client):
    result = client.status()
    if result.get("ok"):
        data = result["data"]
        if data.get("connected"):
            return f"connected to {data['host']}:{data['port']}"
        return "disconnected"
    return f"error: {result.get('error', 'unknown error')}"


def _send_guarded(send_cmd, guard_fn, command):
    g = guard_fn()
    if g:
        return g
    result = send_cmd(command)
    if result.get("ok"):
        return result["data"]
    return f"error: {result.get('error', 'unknown error')}"


def _get_item(send_cmd, guard_fn, item, container, count):
    g = guard_fn()
    if g:
        return g
    parts = ["get"]
    if count is not None:
        parts.append(str(count))
    parts.append(item)
    if container:
        parts.append(container)
    return _send_guarded(send_cmd, guard_fn, " ".join(parts))


def _put_item(send_cmd, guard_fn, item, container, count):
    g = guard_fn()
    if g:
        return g
    parts = ["put"]
    if count is not None:
        parts.append(str(count))
    parts.extend([item, container])
    return _send_guarded(send_cmd, guard_fn, " ".join(parts))


def _equip_item(send_cmd, guard_fn, action, item, body_loc):
    g = guard_fn()
    if g:
        return g
    parts = [action, item]
    if body_loc:
        parts.append(body_loc)
    return _send_guarded(send_cmd, guard_fn, " ".join(parts))


def _cast_spell(send_cmd, guard_fn, spell, target):
    g = guard_fn()
    if g:
        return g
    parts = [f"cast '{spell}'"]
    if target:
        parts.append(target)
    return _send_guarded(send_cmd, guard_fn, " ".join(parts))


def _use_magic_item(send_cmd, guard_fn, mode, item, target_args):
    g = guard_fn()
    if g:
        return g
    parts = [mode, item]
    if target_args:
        parts.append(target_args)
    return _send_guarded(send_cmd, guard_fn, " ".join(parts))


def _shop(send_cmd, guard_fn, action, args):
    g = guard_fn()
    if g:
        return g
    parts = [action]
    if args:
        parts.append(args)
    return _send_guarded(send_cmd, guard_fn, " ".join(parts))


def _practice(send_cmd, guard_fn, skill):
    g = guard_fn()
    if g:
        return g
    if skill:
        return _send_guarded(send_cmd, guard_fn, f"practice {skill}")
    return _send_guarded(send_cmd, guard_fn, "practice")

import json
import socket
from pathlib import Path

PORT_FILE = Path.home() / ".mud_manager" / "port"


class MudDaemonClient:
    """Thin TCP/NDJSON client for the mud_daemon Ruby process."""

    def __init__(self, session="default"):
        self._session = session
        self._port = int(PORT_FILE.read_text().strip())
        self._host = "127.0.0.1"

    def _send(self, request):
        sock = socket.create_connection((self._host, self._port), timeout=10)
        try:
            sock.sendall((json.dumps(request) + "\n").encode("utf-8"))
            data = sock.recv(65536).decode("utf-8")
            return json.loads(data)
        finally:
            sock.close()

    def ping(self):
        return self._send({"cmd": "ping"})

    def connect(self, host="localhost", port=4000, name=None, password=None):
        return self._send({
            "cmd": "connect",
            "session": self._session,
            "host": host,
            "port": port,
            "name": name,
            "password": password,
        })

    def send(self, command):
        return self._send({
            "cmd": "send",
            "session": self._session,
            "command": command,
        })

    def disconnect(self):
        return self._send({
            "cmd": "disconnect",
            "session": self._session,
        })

    def status(self):
        return self._send({
            "cmd": "status",
            "session": self._session,
        })

