def _shop(send_cmd, guard_fn, action, args):
    g = guard_fn()
    if g:
        return g
    parts = [action]
    if args:
        parts.append(args)
    return _send_guarded(send_cmd, guard_fn, " ".join(parts))


def _practice(send_cmd, guard_fn, skill):
    g = guard_fn()
    if g:
